blocks.body:
{
    "level": "A2",
    "intro": "]W tym temacie dowiesz się, jak poprawnie używać słowa <strong>gdzieś, gdziekolwiek, nigdzie, wszędzie</strong> w afirmacjach, zaprzeczeniach i pytania.",
    "rules": [
        {
            "label": "Twierdzenia",
            "color": "emerald",
            "text": "<strong>Gdzieś</strong> – „gdzieś” w wypowiedziach:",
            "example": "Mieszkam gdzieś niedaleko."
        },
        {
            "label": "Zastrzeżenia/pytania",
            "color": "blue",
            "text": "<strong>Gdziekolwiek</strong> – w zastrzeżeniach i pytania:",
            "example": "Nie mieszkam nigdzie w pobliżu."
        },
        {
            "label": "Jedno słowo sprzeciwu",
            "color": "rose",
            "text": "<strong>Nigdzie</strong> – jedno słowo zastrzeżenia:",
            "example": "Mieszkam nigdzie w pobliżu."
        }
    ]
}

{
    "title": "1. Formularze i tłumaczenie",
    "intro": "Oto cztery główne słowa z <code class="font-mono text-xs">niektóre / dowolny</code>:",
    "items": [
        {
            "label": "Twierdzenie",
            "title": "gdzieś",
            "subtitle": "gdzieś"
        },
        {
            "label": "Zaprzeczenie / pytanie",
            "title": "gdzieś",
            "subtitle": "gdzieś/nigdzie (w zastrzeżeniach i pytania)"
        },
        {
            "label": "Negacja",
            "title": "nigdzie",
            "subtitle": "nigdzie[[[CODX_SE G_22]]]Uogólnienie"
        },
        {
            "label": "Узагальнення",
            "title": "wszędzie",
            "subtitle": "wszędzie"
        }
    ]
}

{
    "title": "2. Używaj w afirmacjach, zastrzeżeniach i pytaniach",
    "sections": [
        {
            "label": "Ствердження (Affirmative)",
            "color": "emerald",
            "description": "У ствердженнях частіше вживаємо <strong>somewhere</strong> та <strong>everywhere</strong>.",
            "examples": [
                {
                    "en": "He is somewhere in the building.",
                    "ua": "Він десь у будівлі."
                },
                {
                    "en": "You can see flowers everywhere in spring.",
                    "ua": "Навесні квіти видно всюди."
                }
            ]
        },
        {
            "label": "Заперечення (Negative)",
            "color": "rose",
            "description": "У запереченні вживаємо <strong>anywhere</strong> з <code class="font-mono text-xs">don’t/doesn’t</code> або <strong>nowhere</strong> без додаткового not.",
            "examples": [
                {
                    "en": "Nigdzie nie wychodzę w niedziele.",
                    "ua": "Nigdzie nie wychodzę w niedziele."
                },
                {
                    "en": "Nigdzie nie wychodzę w niedziele.",
                    "ua": "Nigdzie nie wychodzę w niedziele."
                }
            ],
            "note": "❗ Unikaj podwójnych przeczeniach, takich jak <span class="line-through">Nigdzie nie chodzę</span>."
        },
        {
            "label": "Pytania",
            "color": "sky",
            "description": "W pytaniach, których zwykle używamy <strong>wszędzie</strong>.",
            "examples": [
                {
                    "en": "Czy wychodzisz gdzieś w niedziele?",
                    "ua": "Czy jeździsz gdziekolwiek w niedzielę Niedziele?"
                },
                {
                    "en": "Czy jest tu gdzieś w pobliżu coś do jedzenia?",
                    "ua": "Czy jest tu coś do jedzenia w pobliżu?"
                }
            ],
            "note": "<span class="font-semibold">Gdzieś</span> w pytaniu brzmi, jakbyś spodziewał się „jakiegoś konkretnego miejsca”."
        }
    ]
}

{
    "title": "3. Anywhere vs Nowhere",
    "intro": "<strong>Dwie różne formy gramatyczne – to samo znaczenie</strong> w normalnym języku angielskim:",
    "rows": [
        {
            "en": "Nigdzie nie jeżdżę w niedziele.",
            "ua": "Nigdzie nie wychodzę w niedziele.",
            "note": "Sprzeciw poprzez <code class="font-mono text-xs">nie</code> + <strong>nigdzie</strong>."
        },
        {
            "en": "Nigdzie nie idę w niedziele.",
            "ua": "Nigdzie nie idę w niedziele.",
            "note": "Zastrzeżenie jednym słowem <strong>nigdzie</strong>, bez <code class="font-mono text-xs">nie</code>."
        }
    ],
    "warning": "❗ <span class="line-through">I don't gowhere</span> jest niepoprawne gramatycznie w standardowym języku angielskim (jest to podwójne przeczenie)."
}

{
    "title": "4. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Podwójna negacja jak w języku ukraińskim.",
            "wrong": "Donikąd nie idę.",
            "right": " ✅ <span class="font-mono">Nigdzie nie idę.</span> / <span class="font-mono">Donikąd nie idę.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "W pytaniach zamieszanie między <strong>gdzieś</strong> a <strong>gdziekolwiek</strong>.",
            "hint": "<span class="font-mono">Czy jeździsz gdzieś w niedziele?</span> brzmi jak „do jakiegoś konkretnego miejsce”.<br>Zazwyczaj lepiej: <span class="font-mono">Czy jeździsz gdziekolwiek w niedziele?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Używanie <strong>wszędzie</strong> zamiast <strong>gdzieś</strong>.",
            "hint": "<span class="font-mono">Chcę pojechać wszędzie w Londynie.</span> — Chcę pojechać wszędzie w Londynie.<br>Jeśli po prostu „gdzieś”: <span class="font-mono">Chcę pojechać gdzieś w Londynie.</span>"
        }
    ]
}

{
    "title": "5. Krótkie streszczenie",
    "items": [
        "<strong>Gdzieś</strong> – „gdzieś” w wypowiedziach.",
        "<strong>Wszędzie</strong> – „gdzieś/nigdzie” w zastrzeżeniach i pytaniach.",
        "<strong>Nigdzie</strong> – „nigdzie”, sprzeciw jednego w słowo.",
        "<strong>Wszędzie</strong> - „wszędzie”.",
        "Unikaj podwójnej negacji: nie <span class="line-through">Donikąd nie idę</span>, ale <span class="font-mono text-xs">Nigdzie nie idę / Idę nigdzie</span>."
    ]
}

{
    "title": "6. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwe słowo",
    "select_intro": "Wybierz <strong>gdzieś / gdziekolwiek / nigdzie / wszędzie</strong>.",
    "selects": [
        {
            "label": "Nie mogę znaleźć moich kluczy <span class="text-slate-500">(nigdzie)</span>.",
            "prompt": "Nie mogę znaleźć moich kluczy ______."
        },
        {
            "label": "Chce mieszkać <span class="text-slate-500">(gdzieś blisko morza)</span>.",
            "prompt": "Chce mieszkać ______ blisko morza."
        },
        {
            "label": "Czy chcesz jechać <span class="text-slate-500">(gdzieś)</span> dziś wieczorem?",
            "prompt": "Czy chcesz iść ______ tej nocy? wszędzie."
        }
    ],
    "options": [
        "somewhere",
        "anywhere",
        "nowhere",
        "everywhere"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
    "inputs": [
        {
            "before": "Nie chcę iść",
            "after": "dziś wieczorem."
        },
        {
            "before": "Można ",
            "after": "posiedzieć w tym parku. jest pełne. wychodzę gdziekolwiek w soboty."
        },
        {
            "before": "He travels",
            "after": "for work."
        }
    ],
    "rephrase_title": "Вправа 3. Перефразуй",
    "rephrase_intro": "Перепиши речення, використовуючи <strong>anywhere / nowhere</strong>.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "I don’t go anywhere on Saturdays.",
            "example_target": "W soboty nigdzie nie wychodzę."
        },
        {
            "original": "1. W piątkowe wieczory nigdzie nie wychodzę.",
            "placeholder": "Napisz to samo, ale bez...nigdzie"
        },
        {
            "original": "2. Ona nigdzie nie rusza się bez telefonu.",
            "placeholder": "Spróbuj parafrazować znikąd"
        }
    ]
}

{
    "title": "Inne strony z serii Niektórzy / Dowolni",
    "items": [
        {
            "label": "Niektórzy / Dowolni - Ludzie",
            "url": "\/pages\/some-any\/some-any-people"
        },
        {
            "label": "Niektórzy / Dowolni - Rzeczy",
            "url": "\/pages\/some-any\/some-any-things"
        },
        {
            "label": "Niektórzy / Dowolni - Miejsca (aktualne)",
            "current": true
        }
    ]
}
